import os
import psycopg2
from psycopg2.extras import RealDictCursor

DEFAULT_PG_CONFIG = {
    "host": "localhost",
    "port": 5432,
    "dbname": "hackathon_db",
    "user": "admin",
    "password": "demo123",
}

def get_db_connection(
    host: str = DEFAULT_PG_CONFIG["host"],
    port: int = DEFAULT_PG_CONFIG["port"],
    dbname: str = DEFAULT_PG_CONFIG["dbname"],
    user: str = DEFAULT_PG_CONFIG["user"],
    password: str = DEFAULT_PG_CONFIG["password"],
    *,
    autocommit: bool = True,
    dict_cursor: bool = False,
    connect_timeout: int = 5,
):
    if os.getenv("PGHOST") or os.getenv("PGPORT") or os.getenv("PGDATABASE") or os.getenv("PGUSER") or os.getenv("PGPASSWORD"):
        host = os.getenv("PGHOST", host)
        port = int(os.getenv("PGPORT", port))
        dbname = os.getenv("PGDATABASE", dbname)
        user = os.getenv("PGUSER", user)
        password = os.getenv("PGPASSWORD", password)

    cursor_factory = RealDictCursor if dict_cursor else None

    conn = psycopg2.connect(
        host=host,
        port=port,
        dbname=dbname,
        user=user,
        password=password,
        connect_timeout=connect_timeout,
        cursor_factory=cursor_factory,
    )
    conn.autocommit = autocommit
    return conn